// payerChipClass builds the member-colored chip class for a payer.
func payerChipClass(color string) string {
	if color == "" {
		return "bg-surface text-ink-muted"
	}
	return fmt.Sprintf("bg-member-%s-tint text-member-%s-fg", color, color)
}

// currencyOrDefault returns the currency or USD when empty (the add form default).
func currencyOrDefault(currency string) string {
	if currency == "" {
		return "USD"
	}
	return currency
}

